// WalletCarousel.js - Carrusel profesional para las billeteras
// Muestra 3 tarjetas a la vez en desktop, 1 en móvil

import React, { useState, useRef, useEffect } from 'react';
import WalletCard from './WalletCard';
import './WalletCarousel.css';

const WalletCarousel = ({ wallets }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [cardsPerView, setCardsPerView] = useState(3);
  const carouselRef = useRef(null);
  
  // Detectar el tamaño de pantalla para ajustar cuántas tarjetas mostrar
  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth < 640) {
        setCardsPerView(1);
      } else if (window.innerWidth < 1024) {
        setCardsPerView(2);
      } else {
        setCardsPerView(3);
      }
    };
    
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);
  
  const maxIndex = Math.max(0, wallets.length - cardsPerView);
  
  const goToPrevious = () => {
    setCurrentIndex((prev) => Math.max(0, prev - 1));
  };
  
  const goToNext = () => {
    setCurrentIndex((prev) => Math.min(maxIndex, prev + 1));
  };
  
  const goToSlide = (index) => {
    setCurrentIndex(Math.min(maxIndex, Math.max(0, index)));
  };
  
  return (
    <div className="carousel-wrapper">
      <div className="carousel-container">
        <button 
          className="carousel-nav-btn prev" 
          onClick={goToPrevious}
          disabled={currentIndex === 0}
        >
          <span className="nav-icon">←</span>
        </button>
        
        <div className="carousel-viewport">
          <div 
            className="carousel-track-modern"
            style={{
              transform: `translateX(-${currentIndex * (100 / cardsPerView)}%)`
            }}
          >
            {wallets.map((wallet) => (
              <div 
                key={wallet.id} 
                className="carousel-slide"
                style={{ flex: `0 0 ${100 / cardsPerView}%` }}
              >
                <WalletCard
                  name={wallet.name}
                  type={wallet.type}
                  balance={wallet.balance}
                />
              </div>
            ))}
          </div>
        </div>
        
        <button 
          className="carousel-nav-btn next" 
          onClick={goToNext}
          disabled={currentIndex >= maxIndex}
        >
          <span className="nav-icon">→</span>
        </button>
      </div>
      
      {/* Indicadores (dots) */}
      {maxIndex > 0 && (
        <div className="carousel-dots">
          {Array.from({ length: maxIndex + 1 }).map((_, idx) => (
            <button
              key={idx}
              className={`carousel-dot ${currentIndex === idx ? 'active' : ''}`}
              onClick={() => goToSlide(idx)}
            />
          ))}
        </div>
      )}
    </div>
  );
};

export default WalletCarousel;
